#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_hq.zw * 0.05;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;

vec2 uv3 = uv1;
float dist = 60;

uv3 = dist * uv1;

float zu = lum(texture(sampler_noise_lq,vUv));
float shape = 40* (q29+2);
float ky = clamp01(-uv3.y/50+zu/8*cos(16*zu)+.2);
//Faktor an vUv.y drehen

float k1 = uv3.x*(2-.3*vUv.y);;

k1 = k1 - sign (k1)*24; //Verdoppelung
k1 = k1 - sign (k1)*9; //Verdoppelung

int n = 1 ;
float delta = .1;
while (n <= 5)
{
  k1 += 2*(k1-6*n*sign(k1))*ky;
  //Mult. mit n steuert "Breitenwuchs"
  ky = clamp01(ky - delta);
  delta *= 1;
  //delta ist vertikaler Verzweig. abstand
  n++;
}

k1 = clamp(k1,-1.6,1.6);

vec2 rs1 = vec2 (tan(k1),uv3.y);

tree = lum(texture(sampler_noise_hq,rs1*corr))+.2;
//tree = abs(cos(k1));
tree *= vec3 (2.5,.4,.2) * cos(k1);

mask1 = 1;

ret1 = .05*mask1*tree*clamp01(1-pow(2.4*uv1.y,6));

ret = GetPixel(fract(vUv))*.5 + ret1;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv -= 0.5;
vUv *= uAspect.xy;

ret1 = 0; anz = 3; n = 1;

float t_rel = q29;

for (n=1;n<=anz;n++) {
    m =  n-int(t_rel);

    dist = 1-fract(n/anz-fract(-t_rel)/anz);
   //evtl sqrt !

   zoom = q30;
//   zoom = 2 ;

    dist2 = dist*dist;
    inten =  (1-dist2);

    uv2 =zoom*dist*(vUv -.2)-.2; //Blickpunkt vert.

    mask = (uv2.y<=0) * (uv2.y>= -1);
    uv3 = fract(uv2+(m+q28)*vec2(0.3,0))*mask;

    neu = GetPixel (uv3);
    glow = GetBlur1(uv3) * vec3 (0.6,1,1);

    mask = 1-clamp01(12*neu);
    ret1 = ret1*mask + (neu+2*glow)*inten;
//n++;
}

uv4 = vUv + vec2 (-.3,.1); //pos. moon


//clouds
float z = .5*clamp(1/(abs(vUv.y)+.1),0,12);
rs = vec2(vUv.x * z, z);
vec3 clouds = lum(texture(sampler_noise_hq,rs+.04*uTime));
clouds *= clamp01(1-16*vUv.y) * 0.02/(.01+length(uv4));

float mask = clamp01(1-8*ret1.r);

vec3 fog = .0*vec3(0,0,clamp01(vUv.y));


sky = .25*vec3 (.4*clamp01(1-4*vUv.y),
                 .4*clamp01(1-2*vUv.y),
                   clamp01(1-3*vUv.y));
ret = ret1*vec3(0,1,1)+ sky*mask +fog;
ret += clouds * mask;
//ret = GetPixel(vUv+.5)*2;

  fragColor = ret;
}
